import { Network } from '@agentcash/networks';

import { getBalance } from '@/shared/balance';
import { getDepositLink } from '@/shared/utils';

import {
  shouldShowOnboardingCta,
  getOnboardingCta,
} from '@/operations/onboarding-cta';

import type { GlobalFlags } from '@/types';
import type { Wallets } from '@/wallet';
import type { SolanaAddress } from '@agentcash/networks';

export const getWalletInfo = async (
  surface: string,
  wallets: Wallets,
  flags: GlobalFlags
) => {
  return getBalances(surface, wallets, flags);
};

export const listAccountsWithAddresses = (wallets: Wallets) => {
  const {
    evm: { address: evmAddress },
    svm: { address: svmAddress },
  } = wallets;
  return Object.values(Network).map(network => ({
    address:
      network === Network.SOLANA ? (svmAddress as SolanaAddress) : evmAddress,
    network,
  }));
};

export const getBalances = async (
  surface: string,
  wallets: Wallets,
  flags: GlobalFlags
) => {
  const {
    evm: { address: evmAddress },
    svm: { address: svmAddress },
  } = wallets;
  const balanceResults = await Promise.all(
    Object.values(Network).map(network =>
      getBalance(
        surface,
        network === Network.SOLANA
          ? { address: svmAddress, network }
          : { address: evmAddress, network },
        flags
      )
    )
  );

  const accounts = balanceResults
    .filter(balance => balance.isOk())
    .map(balance => {
      const address =
        balance.value.paymentNetwork === Network.SOLANA
          ? (svmAddress as SolanaAddress)
          : evmAddress;

      const depositLink = getDepositLink(
        address,
        flags,
        balance.value.paymentNetwork
      );

      return {
        balance: balance.value.balance,
        network: balance.value.paymentNetwork,
        address,
        depositLink,
      };
    });

  const totalBalance = accounts.reduce(
    (acc, balance) => acc + balance.balance,
    0
  );

  return {
    accounts,
    totalBalance,
    onboardingCta: shouldShowOnboardingCta(totalBalance)
      ? getOnboardingCta(flags)
      : undefined,
  };
};

export const listAccountsWithBalances = async (
  surface: string,
  wallets: Wallets,
  flags: GlobalFlags
) => {
  return getBalances(surface, wallets, flags);
};
